-- Enrichment marathon batch: Change Healthcare, Chartbeat, Chartboost, Chartio, Chatterino, Chatty (Twitch Chat Client), Checkbot, Checkr

-- ── Change Healthcare ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Change Healthcare is a major US healthcare technology company providing claims processing, payment, and data connectivity between payers, providers, and pharmacies. Now part of Optum Insight (UnitedHealth Group), it processes a huge share of the country's medical claims and was the target of a severe February 2024 ransomware attack that disrupted US healthcare billing nationwide.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise / custom quote (B2B healthcare infrastructure, not self-serve SaaS)$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing; not publicly listed$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$10,000+ employees (part of Optum/UnitedHealth Group)$q$, company_size),
  headquarters = COALESCE($q$Nashville, Tennessee, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Change Healthcare Review 2026 - Features, Ownership, and the 2024 Cyberattack$q$, seo_title),
  seo_meta_description = COALESCE($q$An in-depth, factual look at Change Healthcare: what it does, its history, its acquisition by Optum/UnitedHealth, and the 2024 ransomware attack that disrupted US healthcare claims.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Change Healthcare is one of the largest healthcare technology and data connectivity companies in the United States, sitting at the center of the country's medical claims, billing, and payment infrastructure. Its clearinghouse and revenue-cycle-management tools connect hospitals, physician practices, pharmacies, laboratories, and insurance payers, historically routing roughly half of all US medical claims and a large share of pharmacy and eligibility transactions through its systems. The modern company traces its roots to Emdeon (originally spun out of WebMD's transaction-services business in 2007), which was renamed Change Healthcare after a 2015 rebrand, and then combined with McKesson Corporation's health IT unit in 2017 under the Change Healthcare name, with McKesson holding a majority stake. Change Healthcare went public via IPO in 2019 before being acquired by Optum, the health-services arm of UnitedHealth Group, in a roughly 13 billion dollar all-cash deal that closed in October 2022 after a Department of Justice antitrust challenge was rejected in court. Since the acquisition, Change Healthcare has operated as part of Optum Insight, UnitedHealth's data and technology analytics division, and its brand has been progressively folded into Optum's broader technology stack rather than run as an independently marketed product. The single most consequential event in the company's recent history is the February 2024 ransomware attack, which must be represented accurately and neutrally as a matter of historical record. On February 21, 2024, the ALPHV/BlackCat ransomware group gained unauthorized access to Change Healthcare's systems, reportedly after compromising a Citrix remote-access portal that lacked multi-factor authentication (initial access is believed to have occurred around February 12, 2024). The attack forced Change Healthcare to take systems offline, which cascaded into one of the most disruptive healthcare IT outages in US history: pharmacies could not verify insurance benefits, providers could not submit or track claims, remittance and payment processing stalled, and prior-authorization workflows broke down across thousands of hospitals, clinics, and pharmacies nationwide for weeks. UnitedHealth Group disclosed that the incident cost the company 872 million dollars in Q1 2024 alone, with a full-year 2024 impact estimated between 1.35 billion and 1.6 billion dollars, and it extended more than 9 billion dollars in interest-free loans and accelerated payments to affected providers by mid-2024 to ease cash-flow strain. The breach also exposed protected health information for a very large number of individuals, triggering federal investigations, congressional hearings, and numerous lawsuits. For an SEO directory audience researching Change Healthcare, the accurate picture is: a foundational, deeply embedded piece of US healthcare payment plumbing, now owned by Optum/UnitedHealth Group, that suffered a landmark cybersecurity incident in 2024 with lasting financial, regulatory, and reputational consequences, and that continues to operate today as an integrated part of Optum Insight's product portfolio.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '88af77ce-8715-488d-b36b-e1ce0f6b05ce';

