-- ── Chartboost ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chartboost is a mobile game advertising and monetization platform offering a demand-side platform, supply-side/mediation tools, and programmatic ad auctions for mobile app developers. Founded in 2011 by former Tapulous engineers, it was acquired by Zynga in 2021, came under Take-Two Interactive when Take-Two bought Zynga in 2022, and was then sold to adtech company LoopMe in December 2024, which now owns and operates it.$q$, short_description),
  pricing_model = COALESCE($q$Revenue share / programmatic ad platform (not a fixed-fee subscription)$q$, pricing_model),
  starting_price = COALESCE($q$Free to integrate; monetized via ad revenue share and programmatic bidding$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chartboost Review 2026 - Mobile Game Ad Network and Monetization Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$What Chartboost is, how its mobile ad mediation and monetization platform works, its ownership history from Zynga to Take-Two to LoopMe, and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chartboost is a mobile advertising and monetization platform built specifically for mobile game developers, combining a demand-side platform (DSP), a supply-side platform (SSP), and mediation tools that let developers fill ad inventory through programmatic auctions across a large network of demand sources. It was founded in San Francisco in 2011 by Maria Alegre and Sean Fannan, both alumni of Tapulous (the studio behind Tap Tap Revenge, acquired by Disney in 2010), who set out to build a platform giving mobile game developers direct control over promoting, monetizing, and managing their games without relying solely on app-store discovery. Chartboost grew quickly in the 2010s, raising a 19 million dollar Series B led by Sequoia Capital in 2013 and expanding internationally, and it built a reputation as one of the most widely integrated mediation SDKs in mobile gaming, at its peak reporting a global audience of more than 700 million monthly users and tens of billions of monthly ad auctions. Ownership of Chartboost has changed hands multiple times in recent years, which is important context for anyone evaluating the platform today. In 2021, mobile games publisher Zynga acquired Chartboost for approximately 250 million dollars to strengthen its first-party advertising capabilities. When Take-Two Interactive completed its roughly 12.7 billion dollar acquisition of Zynga in May 2022, Chartboost came along as part of that deal and operated as an adtech division within Take-Two's mobile portfolio. In late 2024, Take-Two moved to divest Chartboost as it refocused on premium, AAA game development rather than mobile adtech; that divestiture was completed in December 2024, when adtech company LoopMe announced it had acquired Chartboost from Zynga (Take-Two), with the goal of using Chartboost's supply-side reach to extend LoopMe's brand-advertising business into more mobile apps. As of the most recent available information, Chartboost operates under LoopMe's ownership. For app developers, Chartboost remains primarily relevant as a mediation and monetization SDK integrated into games to serve interstitial, rewarded video, and banner ads, competing with platforms like AppLovin MAX, ironSource/Unity LevelPlay, and Google AdMob mediation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6ade70ee-d432-40f8-bbc1-4f4ace32d4e9';

