-- ── Chatterino ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chatterino is a free, open-source, third-party Twitch chat client for Windows, macOS, and Linux, built to be faster and more customizable than Twitch's built-in web chat. Developed in the open on GitHub by a community of contributors, it supports multiple simultaneous channel tabs, third-party emote services like BetterTTV, FrankerFaceZ, and 7TV, chat filtering and highlighting, and extensive UI customization.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$Open-source community project (volunteer contributors)$q$, company_size),
  headquarters = COALESCE($q$Distributed / open-source community (no formal headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chatterino Review 2026 - Free Open-Source Twitch Chat Client$q$, seo_title),
  seo_meta_description = COALESCE($q$Chatterino is a free, open-source Twitch chat client with multi-channel tabs, third-party emotes, and deep customization. See features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chatterino is a free, open-source desktop chat client built specifically for Twitch, designed as a faster, more feature-rich, and more customizable alternative to Twitch's native web-based chat panel. The current, actively maintained version, commonly referred to as Chatterino 2, is developed openly on GitHub by a small team of maintainers (notably the developers known as fourtf and pajlada) along with community contributors, and it is distributed free of charge for Windows, macOS, Linux, and BSD. Its core appeal to Twitch viewers, moderators, and streamers is performance and control: Chatterino is built to stay smooth and responsive even when a user has many high-traffic channels open simultaneously in separate tabs or split views, which is a common pain point with Twitch's own web chat during large streams or raids. Beyond raw performance, Chatterino integrates support for the major third-party Twitch emote services, including BetterTTV (BTTV), FrankerFaceZ (FFZ), and 7TV, so users see the full range of community emotes that Twitch's default chat does not natively render. It also offers granular customization: users can build custom highlight rules for keywords, usernames, or specific message patterns, set up filters to hide unwanted messages (such as spam or bot commands), adjust themes and fonts, and rearrange the interface to fit their workflow, whether they are a casual viewer, a moderator managing multiple channels, or a streamer monitoring their own chat alongside others. Chatterino also includes built-in commands for common moderation and utility actions, such as blocking or unblocking users, viewing chatter counts, and clearing messages, without needing to type raw Twitch IRC commands. Because it is open source, Chatterino's code is publicly auditable on GitHub, and it has no subscription, ads, or paid tiers; it is maintained through volunteer development and community contributions rather than a commercial business model. Chatterino has become one of the most widely used third-party Twitch chat clients within the streaming community, particularly among viewers and moderators of high-volume channels who need a lighter, faster, more customizable alternative to the native Twitch chat experience.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '75e14f6f-b97e-4e52-b3db-62135190d89e';

