-- ── Chatty (Twitch Chat Client) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Chatty is a free, open-source desktop chat client for Twitch, written in Java, offering an IRC-style interface with Twitch-specific features. It supports joining multiple channels in tabs or separate windows, streamer tools like updating stream title and game from the client, emote autocomplete, and multi-language support, and runs on Windows, macOS, and Linux wherever Java is supported.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Open-source community project (independent developer plus community contributors)$q$, company_size),
  headquarters = COALESCE($q$Distributed / open-source community (no formal headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Russian$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Chatty Review 2026 - Free Java-Based Twitch Chat Client$q$, seo_title),
  seo_meta_description = COALESCE($q$Chatty is a free, open-source Java desktop chat client for Twitch with IRC-style features, streamer tools, and multi-language support. See features and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chatty is a free, open-source desktop chat client purpose-built for Twitch, written in Java, that gives viewers, moderators, and streamers an IRC-inspired chat experience with a range of Twitch-specific enhancements layered on top. Because it is built in Java, Chatty runs cross-platform on any system with a compatible Java runtime, including Windows, macOS, and Linux, and it is distributed in multiple packaged forms, including a portable version bundled with its own Java runtime environment so users without Java already installed can still run it. Chatty's interface lets users join numerous Twitch channels at once, organized as tabs, split views, or separate popped-out windows, which suits both casual viewers following several streams and moderators or streamers who need to keep an eye on multiple chats simultaneously. What sets Chatty apart from a purely generic IRC client is its deep set of Twitch-aware conveniences: streamers can update their stream title, category or game, and tags directly from within the chat client, and can even trigger ad commercials using a configurable hotkey, all without switching over to the Twitch dashboard in a browser. For viewers, Chatty provides emote autocomplete, the ability to locally hide specific emotes they don't want to see, and support for standard emoji shortcodes. The tool has also been localized by its community into several languages, including German, French, Russian, and Japanese, in addition to English, reflecting a long-running, internationally active user base. Chatty has existed as a free, community-maintained project for many years, predating some of its more recently developed alternatives, and it remains actively referenced in Twitch tool round-ups and creator resource guides as a lightweight, no-cost option for anyone who wants more control and fewer distractions than Twitch's native web chat, without necessarily needing every advanced customization feature found in some newer third-party clients. It has no company, subscription, or paid tier behind it; the software is free to download from its official GitHub-hosted project pages.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '07f7e3a2-3549-492f-9f44-b804dbf9984a';

