-- ── Checkbot ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Checkbot is a Chrome and Edge browser extension for technical SEO, broken link checking, and website auditing, letting developers and SEOs crawl hundreds of pages at once to catch issues like broken links, duplicate titles, missing meta tags, invalid HTML/CSS/JavaScript, and mobile-friendliness problems. Built by independent developer Sean Wilson, it offers a free tier for unlimited small-site checks plus a paid Pro tier with deeper crawl and export features.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (free tier plus paid Pro subscription)$q$, pricing_model),
  starting_price = COALESCE($q$Free; paid Pro plans available (exact pricing set by developer, billed quarterly or yearly)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$1-10 employees (independent developer-led product)$q$, company_size),
  headquarters = COALESCE($q$Edinburgh, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Checkbot Review 2026 - Browser-Based SEO and Broken Link Checker Extension$q$, seo_title),
  seo_meta_description = COALESCE($q$Checkbot is a Chrome/Edge extension for SEO audits, broken link checking, and site crawling. See features, pricing, pros, cons, and FAQs for developers and SEOs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Checkbot is a browser extension for Google Chrome and Microsoft Edge that gives web developers, technical SEOs, and site owners a fast way to audit a website for common SEO, performance, and security issues directly from the browser, without needing to set up a separate crawling service or install desktop software. It was created by Sean Wilson, an independent web app developer based in Edinburgh, UK, who built the tool out of a personal collection of testing utilities he had accumulated while consulting on web projects, aiming to automate away tedious, error-prone manual checks that developers and SEOs otherwise had to perform by hand. Once installed, Checkbot can crawl hundreds of pages on a website simultaneously, checking for more than 50 common problems based on best practices recommended by organizations like Google and Mozilla. Its SEO-focused checks include a broken link checker, analysis of page titles, meta descriptions, and headings, detection of duplicate content and duplicate titles, validation of canonical URLs, checks for missing or unoptimized image ALT tags, robots.txt validation, redirect chain analysis, and identification of 404 and other error pages. Beyond core SEO, Checkbot also validates HTML, CSS, and JavaScript for errors, flags deprecated web platform features, checks for mobile-friendliness, and runs basic website security checks (such as insecure content or missing security headers), making it a broader website health tool rather than a narrowly scoped SEO checker. Checkbot uses a freemium model: the free version allows unlimited checks on small websites at any frequency, which is enough for many individual site owners or small-business audits. The paid Checkbot Pro tier unlocks features aimed at professional and agency users, including the ability to crawl localhost or password-protected staging sites, generate PDF audit reports for clients, export full crawl results to CSV for further analysis, customize crawl settings and depth, and check sites sitting behind HTTP authentication. With more than 80,000 users on the Chrome Web Store and a 4.9-out-of-5 star rating, Checkbot has built a loyal following among freelance developers, in-house web teams, and technical SEOs who want a lightweight, in-browser alternative to heavier desktop crawlers like Screaming Frog for quick, ad hoc site audits.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '84f4c594-16fc-438c-9ffa-a201e324ee91';

